/**
 * generate-coverage-dashboard.mjs
 *
 * Auto-discovers coverage stacks from a directory of ReportGenerator artifacts
 * and produces:
 *   - index.html              (visual dashboard with sparklines, deltas, gates)
 *   - badge_combined.svg      (shields.io-style badge with average line coverage)
 *   - history.json            (appends current run for trend tracking)
 *
 * Usage:
 *   node generate-coverage-dashboard.mjs <artifacts-dir> [options]
 *
 * Options:
 *   --title "My Project"        Override project title
 *   --repo-url "https://..."    Override repo URL
 *   --history <path>            Path to history.json (read + write)
 *   --config <path>             Path to coverage-config.json (gate thresholds)
 *
 * Contract per stack directory:
 *   <artifacts-dir>/<stack-name>/
 *     SummaryGithub.md    — generated by ReportGenerator (MarkdownSummaryGithub)
 *     badge_combined.svg  — generated by ReportGenerator (Badges)
 *     index.html          — generated by ReportGenerator (Html)
 *
 * Zero npm dependencies — uses only Node.js built-ins (fs, path).
 */

import {
  existsSync,
  mkdirSync,
  readdirSync,
  readFileSync,
  statSync,
  writeFileSync,
} from "node:fs";
import { dirname, join, resolve } from "node:path";

// ─── CLI args ────────────────────────────────────────────────────────────────

const args = process.argv.slice(2);
const artifactsDir = resolve(args[0] ?? "coveragereport");

function flagValue(name) {
  const idx = args.indexOf(name);
  return idx !== -1 && idx + 1 < args.length ? args[idx + 1] : undefined;
}

function deriveProjectTitle() {
  const explicit = flagValue("--title");
  if (explicit) {
    return explicit;
  }
  const repo = process.env.GITHUB_REPOSITORY;
  if (repo) {
    return repo
      .split("/")
      .pop()
      .replace(/[-_]/g, " ")
      .replace(/\b\w/g, (c) => c.toUpperCase());
  }
  return "Coverage";
}

function deriveRepoUrl() {
  const explicit = flagValue("--repo-url");
  if (explicit) {
    return explicit;
  }
  const repo = process.env.GITHUB_REPOSITORY;
  if (repo) {
    return `https://github.com/${repo}/actions`;
  }
  return "#";
}

const projectTitle = deriveProjectTitle();
const repoUrl = deriveRepoUrl();
const historyPath = flagValue("--history");
const configPath = flagValue("--config");

// ─── Constants ───────────────────────────────────────────────────────────────

const STACK_ICONS = {
  core: "🎮",
  cli: "🎮",
  dotnet: "⚙️",
  python: "🐍",
  iac: "☁️",
  typescript: "📦",
  go: "🦫",
  java: "☕",
  backend: "⚙️",
  frontend: "🌐",
  ml: "🧠",
  infra: "🏗️",
  api: "🔌",
  worker: "⚡",
  shared: "📚",
  e2e: "🧪",
};

const DEFAULT_ICON = "📦";

const COLOR_HEX = {
  green: "#22c55e",
  yellow: "#eab308",
  red: "#ef4444",
  blue: "#60a5fa",
  muted: "#334155",
};

const DEFAULT_GATE_THRESHOLD = 80;

// ─── Discover stacks ────────────────────────────────────────────────────────

function discoverStacks(dir) {
  if (!existsSync(dir)) {
    return [];
  }
  const entries = readdirSync(dir, { withFileTypes: true });
  return entries
    .filter((e) => e.isDirectory())
    .map((e) => {
      const stackDir = join(dir, e.name);
      const summaryPath = join(stackDir, "SummaryGithub.md");
      const hasReport = safeExists(join(stackDir, "index.html"));
      const summary = parseSummary(summaryPath);
      const icon = resolveIcon(e.name);
      const title = summary.title ?? formatTitle(e.name);
      const testStats = parseTestStats(stackDir);
      return {
        name: e.name,
        title,
        icon,
        coverage: summary,
        hasReport,
        testStats,
      };
    })
    .sort((a, b) => a.name.localeCompare(b.name));
}

function safeExists(path) {
  try {
    statSync(path);
    return true;
  } catch {
    return false;
  }
}

// ─── Parse test-stats.json ──────────────────────────────────────────────────

function parseTestStats(stackDir) {
  const statsPath = join(stackDir, "test-stats.json");
  try {
    const content = readFileSync(statsPath, "utf8");
    const data = JSON.parse(content);
    return {
      total: data.total ?? null,
      passed: data.passed ?? null,
      failed: data.failed ?? null,
      skipped: data.skipped ?? null,
      duration: data.duration ?? null,
    };
  } catch {
    return null;
  }
}

// ─── Parse SummaryGithub.md ─────────────────────────────────────────────────

function parseSummary(path) {
  try {
    const content = readFileSync(path, "utf8");
    return {
      title: extractTitle(content),
      line: extractPercentage(
        content,
        /line coverage[^|]*\|\s*\**(\d+(?:\.\d+)?%)\**/i,
      ),
      branch: extractPercentage(
        content,
        /branch coverage[^|]*\|\s*\**(\d+(?:\.\d+)?%)\**/i,
      ),
    };
  } catch {
    return { title: null, line: null, branch: null };
  }
}

function extractTitle(text) {
  const match = text.match(/^#\s+Summary\s*[-–—]\s*(.+)$/m);
  return match ? match[1].trim() : null;
}

function extractPercentage(text, regex) {
  const match = text.match(regex);
  return match ? match[1] : null;
}

// ─── Helpers ────────────────────────────────────────────────────────────────

function resolveIcon(name) {
  const lower = name.toLowerCase();
  for (const [key, icon] of Object.entries(STACK_ICONS)) {
    if (lower.includes(key)) {
      return icon;
    }
  }
  return DEFAULT_ICON;
}

function formatTitle(name) {
  return name
    .replace(/[-_]/g, " ")
    .replace(/\b\w/g, (c) => c.toUpperCase());
}

function pctToNumber(pct) {
  if (!pct) {
    return null;
  }
  return parseFloat(pct.replace("%", ""));
}

function colorClass(pct) {
  const n = pctToNumber(pct);
  if (n === null) {
    return "muted";
  }
  if (n >= 80) {
    return "green";
  }
  if (n >= 60) {
    return "yellow";
  }
  return "red";
}

function gaugeOffset(pct) {
  const n = pctToNumber(pct);
  if (n === null) {
    return 100;
  }
  return (100 - n).toFixed(1);
}

function displayValue(pct) {
  return pct ?? "N/A";
}

function escapeHtml(str) {
  if (typeof str !== "string") {
    return str;
  }
  return str
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#39;");
}

function formatNumber(n) {
  if (n === null || n === undefined) {
    return "—";
  }
  return n.toLocaleString("en-US");
}

function parseDurationToSeconds(str) {
  if (!str) {
    return 0;
  }
  let seconds = 0;
  const msMatch = str.match(/([\d.]+)\s*ms/i);
  const minMatch = str.match(/(\d+)\s*m(?!s)/i);
  const secMatch = str.match(/([\d.]+)\s*s(?!.*ms)/i);
  if (msMatch) {
    seconds += parseFloat(msMatch[1]) / 1000;
  }
  if (minMatch) {
    seconds += parseInt(minMatch[1]) * 60;
  }
  if (secMatch) {
    seconds += parseFloat(secMatch[1]);
  }
  return seconds;
}

function formatDuration(seconds) {
  if (seconds <= 0) {
    return "—";
  }
  if (seconds < 60) {
    return `${Math.round(seconds)}s`;
  }
  const m = Math.floor(seconds / 60);
  const s = Math.round(seconds % 60);
  return s > 0 ? `${m}m ${s}s` : `${m}m`;
}

function average(values) {
  const nums = values.map(pctToNumber).filter((n) => n !== null);
  if (nums.length === 0) {
    return null;
  }
  return `${(nums.reduce((a, b) => a + b, 0) / nums.length).toFixed(1)}%`;
}

// ─── History management ─────────────────────────────────────────────────────

function loadHistory(path) {
  if (!path) {
    return { runs: [] };
  }
  try {
    const content = readFileSync(path, "utf8");
    const data = JSON.parse(content);
    return { runs: Array.isArray(data.runs) ? data.runs : [] };
  } catch {
    return { runs: [] };
  }
}

function saveHistory(path, history) {
  if (!path) {
    return;
  }
  const dir = dirname(path);
  if (!existsSync(dir)) {
    mkdirSync(dir, { recursive: true });
  }
  writeFileSync(path, JSON.stringify(history, null, 2), "utf8");
}

function appendCurrentRun(history, stacks, overall) {
  const run = {
    date: new Date().toISOString(),
    sha: process.env.GITHUB_SHA?.slice(0, 7) ?? "local",
    runNumber: parseInt(process.env.GITHUB_RUN_NUMBER ?? "0", 10),
    overall: {
      line: pctToNumber(overall.line),
      branch: pctToNumber(overall.branch),
    },
    stacks: {},
  };
  let totalTests = 0;
  let totalDurationS = 0;

  for (const s of stacks) {
    const entry = {
      line: pctToNumber(s.coverage.line),
      branch: pctToNumber(s.coverage.branch),
    };
    if (s.testStats) {
      entry.tests = s.testStats.total;
      entry.skipped = s.testStats.skipped;
      entry.durationS = parseDurationToSeconds(s.testStats.duration);
      totalTests += s.testStats.total ?? 0;
      totalDurationS += entry.durationS;
    }
    run.stacks[s.name] = entry;
  }

  if (totalTests > 0) {
    run.overall.tests = totalTests;
    run.overall.durationS = totalDurationS;
  }

  history.runs.push(run);
  return history;
}

// ─── Delta computation ──────────────────────────────────────────────────────

function computeDelta(current, previous) {
  if (current === null || previous === null || previous === undefined) {
    return null;
  }
  return current - previous;
}

function formatDelta(delta) {
  if (delta === null) {
    return "";
  }
  const abs = Math.abs(delta);
  const value = abs < 0.05 ? "0.0%" : `${abs.toFixed(1)}%`;
  if (abs < 0.05) {
    return `<span class="delta delta-flat">— 0.0%</span>`;
  }
  if (delta > 0) {
    return `<span class="delta delta-up">▲ +${value}</span>`;
  }
  return `<span class="delta delta-down">▼ -${value}</span>`;
}

function getStackDelta(history, stackName, metric) {
  const runs = history.runs;
  if (runs.length < 2) {
    return null;
  }
  const prev = runs[runs.length - 2];
  const curr = runs[runs.length - 1];
  const prevVal = prev.stacks?.[stackName]?.[metric] ?? null;
  const currVal = curr.stacks?.[stackName]?.[metric] ?? null;
  return computeDelta(currVal, prevVal);
}

function getOverallDelta(history, metric) {
  const runs = history.runs;
  if (runs.length < 2) {
    return null;
  }
  const prev = runs[runs.length - 2];
  const curr = runs[runs.length - 1];
  return computeDelta(
    curr.overall?.[metric] ?? null,
    prev.overall?.[metric] ?? null,
  );
}

// ─── Sparkline SVG generation ───────────────────────────────────────────────

function generateSparkline(values, colorName = "green") {
  if (!values || values.length < 2) {
    return "";
  }
  const clean = values.map((v) =>
    v === null || v === undefined ? 0 : v,
  );
  const width = 200;
  const height = 28;
  const padding = 2;
  const min = Math.min(...clean) - padding;
  const max = Math.max(...clean) + padding;
  const range = max - min || 1;

  const coords = clean.map((v, i) => ({
    x: parseFloat(((i / (clean.length - 1)) * width).toFixed(1)),
    y: parseFloat(
      (height - ((v - min) / range) * height).toFixed(1),
    ),
  }));

  const polyline = coords.map((p) => `${p.x},${p.y}`).join(" ");
  const areaPoints = `0,${height} ${polyline} ${width},${height}`;
  const last = coords[coords.length - 1];
  const dotFill = COLOR_HEX[colorName] ?? COLOR_HEX.green;

  return `<svg viewBox="0 0 ${width} ${height}" preserveAspectRatio="none">
      <polygon class="spark-area spark-area-${colorName}" points="${areaPoints}"/>
      <polyline class="spark-line spark-line-${colorName}" points="${polyline}"/>
      <circle cx="${last.x}" cy="${last.y}" r="2" fill="${dotFill}"/>
    </svg>`;
}

function generateHeroSparkline(values) {
  if (!values || values.length < 2) {
    return "";
  }
  const clean = values.map((v) =>
    v === null || v === undefined ? 0 : v,
  );
  const width = 300;
  const height = 50;
  const padding = 2;
  const min = Math.min(...clean) - padding;
  const max = Math.max(...clean) + padding;
  const range = max - min || 1;

  const coords = clean.map((v, i) => ({
    x: parseFloat(((i / (clean.length - 1)) * width).toFixed(1)),
    y: parseFloat(
      (height - ((v - min) / range) * height).toFixed(1),
    ),
  }));

  const polyline = coords.map((p) => `${p.x},${p.y}`).join(" ");
  const areaPoints = `0,${height} ${polyline} ${width},${height}`;
  const last = coords[coords.length - 1];

  return `<svg viewBox="0 0 ${width} ${height}" preserveAspectRatio="none">
      <defs><linearGradient id="heroGrad" x1="0" y1="0" x2="0" y2="1">
        <stop offset="0%" stop-color="#60a5fa" stop-opacity=".3"/>
        <stop offset="100%" stop-color="#60a5fa" stop-opacity="0"/>
      </linearGradient></defs>
      <polygon points="${areaPoints}" fill="url(#heroGrad)" opacity=".3"/>
      <polyline points="${polyline}" fill="none" stroke="#60a5fa" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/>
      <circle cx="${last.x}" cy="${last.y}" r="3.5" fill="#a78bfa" style="filter:drop-shadow(0 0 4px rgba(167,139,250,.5))"/>
    </svg>`;
}

function getStackLineHistory(history, stackName) {
  return history.runs.map((r) => r.stacks?.[stackName]?.line ?? null);
}

function getOverallLineHistory(history) {
  return history.runs.map((r) => r.overall?.line ?? null);
}

// ─── Coverage gates ─────────────────────────────────────────────────────────

function loadConfig(path) {
  if (!path) {
    return { gates: {} };
  }
  try {
    const content = readFileSync(path, "utf8");
    return JSON.parse(content);
  } catch {
    return { gates: {} };
  }
}

function getGateThreshold(config, stackName) {
  return (
    config.gates?.[stackName]?.line ??
    config.gates?.default?.line ??
    DEFAULT_GATE_THRESHOLD
  );
}

function evaluateGate(linePct, threshold) {
  if (linePct === null) {
    return null;
  }
  return linePct >= threshold;
}

function gateBadgeHtml(passed) {
  if (passed === null) {
    return "";
  }
  if (passed) {
    return `<span class="gate-badge gate-pass">✓ Pass</span>`;
  }
  return `<span class="gate-badge gate-fail">✗ Fail</span>`;
}

// ─── Badge SVG generator ────────────────────────────────────────────────────

function badgeColor(pct) {
  if (pct >= 80) {
    return "#4c1";
  }
  if (pct >= 60) {
    return "#dfb317";
  }
  return "#e05d44";
}

function escapeXml(text) {
  return text
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;");
}

function generateBadgeSvg(label, value, color) {
  const charWidth = 6.7;
  const padding = 10;
  const labelWidth = Math.round(label.length * charWidth + padding);
  const valueWidth = Math.round(value.length * charWidth + padding);
  const totalWidth = labelWidth + valueWidth;
  const labelX = (labelWidth / 2) * 10;
  const valueX = (labelWidth + valueWidth / 2) * 10;
  const safeLabel = escapeXml(label);
  const safeValue = escapeXml(value);

  return `<svg xmlns="http://www.w3.org/2000/svg" width="${totalWidth}" height="20" role="img" aria-label="${safeLabel}: ${safeValue}">
  <title>${safeLabel}: ${safeValue}</title>
  <linearGradient id="s" x2="0" y2="100%"><stop offset="0" stop-color="#bbb" stop-opacity=".1"/><stop offset="1" stop-opacity=".1"/></linearGradient>
  <clipPath id="r"><rect width="${totalWidth}" height="20" rx="3" fill="#fff"/></clipPath>
  <g clip-path="url(#r)">
    <rect width="${labelWidth}" height="20" fill="#555"/>
    <rect x="${labelWidth}" width="${valueWidth}" height="20" fill="${color}"/>
    <rect width="${totalWidth}" height="20" fill="url(#s)"/>
  </g>
  <g fill="#fff" text-anchor="middle" font-family="Verdana,Geneva,DejaVu Sans,sans-serif" text-rendering="geometricPrecision" font-size="110">
    <text aria-hidden="true" x="${labelX}" y="150" fill="#010101" fill-opacity=".3" transform="scale(.1)">${safeLabel}</text>
    <text x="${labelX}" y="140" transform="scale(.1)" fill="#fff">${safeLabel}</text>
    <text aria-hidden="true" x="${valueX}" y="150" fill="#010101" fill-opacity=".3" transform="scale(.1)">${safeValue}</text>
    <text x="${valueX}" y="140" transform="scale(.1)" fill="#fff">${safeValue}</text>
  </g>
</svg>`;
}

// ─── Dashboard HTML ─────────────────────────────────────────────────────────

function buildCard(stack, { history, config }) {
  const lc = colorClass(stack.coverage.line);
  const bc = colorClass(stack.coverage.branch);
  const lo = gaugeOffset(stack.coverage.line);
  const bo = gaugeOffset(stack.coverage.branch);
  const lt = displayValue(stack.coverage.line);
  const bt = displayValue(stack.coverage.branch);

  const threshold = getGateThreshold(config, stack.name);
  const linePct = pctToNumber(stack.coverage.line);
  const gateResult = evaluateGate(linePct, threshold);
  const gateBadge = gateBadgeHtml(gateResult);

  const lineDelta = getStackDelta(history, stack.name, "line");
  const branchDelta = getStackDelta(history, stack.name, "branch");

  const lineHistory = getStackLineHistory(history, stack.name);
  const sparkColor = colorClass(stack.coverage.line);
  const sparkSvg = generateSparkline(lineHistory, sparkColor);
  const sparkHtml = sparkSvg
    ? `<div class="card-sparkline">${sparkSvg}</div>`
    : "";

  const ts = stack.testStats;
  const statsItems = [];
  if (ts) {
    statsItems.push(
      `<div class="card-stat"><span class="card-stat-value">${formatNumber(ts.total)}</span><span class="card-stat-label">Tests</span></div>`,
    );
    if (ts.duration) {
      statsItems.push(
        `<div class="card-stat"><span class="card-stat-value">${ts.duration}</span><span class="card-stat-label">Duration</span></div>`,
      );
    }
    statsItems.push(
      `<div class="card-stat"><span class="card-stat-value">${ts.skipped ?? 0}</span><span class="card-stat-label">Skipped</span></div>`,
    );
  }
  statsItems.push(
    `<div class="card-stat"><span class="card-stat-value">≥${threshold}%</span><span class="card-stat-label">Gate</span></div>`,
  );
  const statsHtml = `<div class="card-stats">${statsItems.join("")}</div>`;

  const links = stack.hasReport
    ? `<div class="card-links">
            <a class="card-link" href="${escapeHtml(stack.name)}/index.html">📊 HTML</a>
            <a class="card-link" href="${escapeHtml(stack.name)}/SummaryGithub.md">📝 Markdown</a>
          </div>`
    : `<div class="card-links"><span class="card-link muted">No report</span></div>`;

  return `
        <div class="card">
          <div class="card-header">
            <div class="card-title">${escapeHtml(stack.icon)} ${escapeHtml(stack.title)}</div>
            ${gateBadge}
          </div>
          <div class="gauges">
            <div class="gauge">
              <svg viewBox="0 0 36 36"><circle class="gauge-bg" cx="18" cy="18" r="15.9"/><circle class="gauge-fill color-${lc}" cx="18" cy="18" r="15.9" stroke-dasharray="100" stroke-dashoffset="${lo}"/></svg>
              <div class="gauge-text text-${lc}">${lt}</div>
              <div class="gauge-label">Lines</div>
              ${formatDelta(lineDelta)}
            </div>
            <div class="gauge">
              <svg viewBox="0 0 36 36"><circle class="gauge-bg" cx="18" cy="18" r="15.9"/><circle class="gauge-fill color-${bc}" cx="18" cy="18" r="15.9" stroke-dasharray="100" stroke-dashoffset="${bo}"/></svg>
              <div class="gauge-text text-${bc}">${bt}</div>
              <div class="gauge-label">Branches</div>
              ${formatDelta(branchDelta)}
            </div>
          </div>
          ${sparkHtml}
          ${statsHtml}
          ${links}
        </div>`;
}

function buildHeroStatsHtml(stacks, runsTracked) {
  const hasTestStats = stacks.some((s) => s.testStats !== null);
  const items = [];

  if (hasTestStats) {
    const totalTests = stacks.reduce(
      (sum, s) => sum + (s.testStats?.total ?? 0),
      0,
    );
    const totalDurationS = stacks.reduce(
      (sum, s) => sum + parseDurationToSeconds(s.testStats?.duration),
      0,
    );

    if (totalTests > 0) {
      items.push(
        `<div class="hero-stat"><span class="hero-stat-value">${formatNumber(totalTests)}</span><span class="hero-stat-label">Total tests</span></div>`,
      );
    }
    if (totalDurationS > 0) {
      items.push(
        `<div class="hero-stat"><span class="hero-stat-value">${formatDuration(totalDurationS)}</span><span class="hero-stat-label">Total duration</span></div>`,
      );
    }
  }

  items.push(
    `<div class="hero-stat"><span class="hero-stat-value">${stacks.length}</span><span class="hero-stat-label">Stacks</span></div>`,
  );
  items.push(
    `<div class="hero-stat"><span class="hero-stat-value">${runsTracked}</span><span class="hero-stat-label">Runs tracked</span></div>`,
  );

  return items.join("\n          ");
}

function buildHeroCard(avgLine, avgBranch, { history, stacks }) {
  const lc = colorClass(avgLine);
  const bc = colorClass(avgBranch);
  const lo = gaugeOffset(avgLine);
  const bo = gaugeOffset(avgBranch);
  const lt = displayValue(avgLine);
  const bt = displayValue(avgBranch);

  const lineDelta = getOverallDelta(history, "line");
  const branchDelta = getOverallDelta(history, "branch");

  const overallHistory = getOverallLineHistory(history);
  const sparkSvg = generateHeroSparkline(overallHistory);
  const runsTracked = history.runs.length;

  const sparkHtml = sparkSvg
    ? `<div class="hero-trend">
            <span class="hero-trend-label">Line coverage — all ${runsTracked} runs</span>
            <div class="hero-sparkline-wide">${sparkSvg}</div>
          </div>`
    : "";

  return `
      <div class="hero-card">
        <div class="hero-title">🏆 Overall Coverage</div>
        <div class="hero-gauges">
          <div class="gauge hero-gauge">
            <svg viewBox="0 0 36 36"><circle class="gauge-bg" cx="18" cy="18" r="15.9"/><circle class="gauge-fill color-${lc}" cx="18" cy="18" r="15.9" stroke-dasharray="100" stroke-dashoffset="${lo}"/></svg>
            <div class="gauge-text hero-gauge-text text-${lc}">${lt}</div>
            <div class="gauge-label">Lines</div>
            ${formatDelta(lineDelta)}
          </div>
          <div class="gauge hero-gauge">
            <svg viewBox="0 0 36 36"><circle class="gauge-bg" cx="18" cy="18" r="15.9"/><circle class="gauge-fill color-${bc}" cx="18" cy="18" r="15.9" stroke-dasharray="100" stroke-dashoffset="${bo}"/></svg>
            <div class="gauge-text hero-gauge-text text-${bc}">${bt}</div>
            <div class="gauge-label">Branches</div>
            ${formatDelta(branchDelta)}
          </div>
        </div>
        ${sparkHtml}
        <div class="hero-stats">
          ${buildHeroStatsHtml(stacks, runsTracked)}
        </div>
      </div>`;
}

function generateDashboardHtml(
  stacks,
  overall,
  timestamp,
  { history, config },
) {
  const heroCard = buildHeroCard(overall.line, overall.branch, {
    history,
    stacks,
  });
  const cards = stacks
    .map((s) => buildCard(s, { history, config }))
    .join("\n");
  const sha = process.env.GITHUB_SHA?.slice(0, 7) ?? "";
  const runNumber = process.env.GITHUB_RUN_NUMBER ?? "";

  const footerParts = [`Last updated: ${timestamp}`];
  if (runNumber) {
    footerParts.push(`Run #${runNumber}`);
  }
  if (sha) {
    footerParts.push(`<code>${sha}</code>`);
  }
  footerParts.push(
    `Generated by <a href="${repoUrl}">GitHub Actions</a>`,
  );

  return `<!doctype html>
<html lang="en">
<head>
  <meta charset="utf-8"/>
  <meta name="viewport" content="width=device-width,initial-scale=1"/>
  <title>${projectTitle} — Coverage Dashboard</title>
  <style>
    *,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
    body{font-family:'Segoe UI',system-ui,-apple-system,sans-serif;background:#0a0e1a;color:#e2e8f0;min-height:100vh;padding:48px 32px}
    .container{max-width:1200px;margin:0 auto}

    header{text-align:center;margin-bottom:48px}
    header h1{font-size:2rem;font-weight:700;letter-spacing:-.5px}
    header h1 span{background:linear-gradient(135deg,#60a5fa,#a78bfa);background-clip:text;-webkit-background-clip:text;-webkit-text-fill-color:transparent}
    header p{color:#64748b;margin-top:8px;font-size:.95rem}
    header code{background:#1e293b;padding:2px 6px;border-radius:4px;font-size:.85rem;color:#94a3b8}

    .gate-legend{display:flex;gap:20px;justify-content:center;margin-top:8px;font-size:.75rem;color:#64748b}
    .gate-legend-item{display:flex;align-items:center;gap:5px}
    .gate-legend-dot{width:8px;height:8px;border-radius:50%}
    .gate-legend-dot.pass{background:#22c55e}
    .gate-legend-dot.fail{background:#ef4444}

    .hero-card{background:linear-gradient(135deg,#111827 0%,#1a1f3a 100%);border:1px solid #2d3561;border-radius:20px;padding:36px 40px;margin-bottom:32px;display:flex;flex-direction:column;align-items:center;gap:24px;position:relative;overflow:hidden}
    .hero-card::before{content:'';position:absolute;inset:0;background:radial-gradient(ellipse at 50% 0%,rgba(99,102,241,.08) 0%,transparent 70%);pointer-events:none}
    .hero-title{font-size:1.3rem;font-weight:700;letter-spacing:-.3px;text-align:center}
    .hero-gauges{display:flex;gap:48px;justify-content:center;align-items:center;flex-wrap:wrap}
    .hero-gauge svg{width:120px;height:120px}
    .hero-gauge-text{width:120px;height:120px;font-size:1.5rem}

    .hero-trend{display:flex;flex-direction:column;align-items:center;gap:8px;margin-top:8px;width:100%}
    .hero-trend-label{font-size:.75rem;color:#64748b;text-transform:uppercase;letter-spacing:1px}
    .hero-sparkline-wide svg{width:100%;max-width:600px;height:60px}

    .hero-stats{display:flex;gap:32px;justify-content:center;flex-wrap:wrap;margin-top:4px}
    .hero-stat{display:flex;flex-direction:column;align-items:center;gap:2px}
    .hero-stat-value{font-size:1.1rem;font-weight:700;color:#e2e8f0}
    .hero-stat-label{font-size:.7rem;color:#64748b;text-transform:uppercase;letter-spacing:.5px}

    .section-title{font-size:.85rem;color:#475569;text-transform:uppercase;letter-spacing:1.5px;font-weight:600;margin:36px 0 16px;padding-left:4px}

    .grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(280px,1fr));gap:20px}

    .card{background:#111827;border:1px solid #1e293b;border-radius:16px;padding:28px 24px;text-decoration:none;color:inherit;transition:border-color .2s,box-shadow .2s,transform .15s;display:flex;flex-direction:column;align-items:center;gap:16px;position:relative;overflow:hidden}
    .card:hover{border-color:#3b82f6;box-shadow:0 0 24px rgba(59,130,246,.12);transform:translateY(-2px)}

    .card-header{display:flex;align-items:center;justify-content:center;gap:8px;width:100%}
    .card-title{font-size:1.05rem;font-weight:600;text-align:center}

    .gate-badge{font-size:.6rem;padding:2px 7px;border-radius:5px;font-weight:700;letter-spacing:.3px;text-transform:uppercase;white-space:nowrap;flex-shrink:0}
    .gate-pass{background:rgba(34,197,94,.12);color:#22c55e;border:1px solid rgba(34,197,94,.2)}
    .gate-fail{background:rgba(239,68,68,.12);color:#ef4444;border:1px solid rgba(239,68,68,.2)}

    .gauges{display:flex;gap:24px;justify-content:center;align-items:center;width:100%}
    .gauge{position:relative;display:flex;flex-direction:column;align-items:center;gap:6px}
    .gauge svg{width:90px;height:90px;transform:rotate(-90deg);overflow:visible}
    .gauge-bg{fill:none;stroke:#1e293b;stroke-width:6}
    .gauge-fill{fill:none;stroke-width:6;stroke-linecap:round;transition:stroke-dashoffset .8s ease}
    .gauge-text{position:absolute;top:0;left:0;width:90px;height:90px;display:flex;align-items:center;justify-content:center;font-size:1.15rem;font-weight:700}
    .gauge-label{font-size:.7rem;color:#94a3b8;text-transform:uppercase;letter-spacing:.5px;font-weight:500}

    .delta{font-size:.72rem;font-weight:600;padding:2px 7px;border-radius:5px;margin-top:-2px}
    .delta-up{background:rgba(34,197,94,.1);color:#22c55e}
    .delta-down{background:rgba(239,68,68,.1);color:#ef4444}
    .delta-flat{background:rgba(148,163,184,.08);color:#64748b}

    .card-sparkline{width:100%;display:flex;justify-content:center}
    .card-sparkline svg{width:100%;max-width:220px;height:32px}

    .spark-line{fill:none;stroke-width:1.5;stroke-linecap:round;stroke-linejoin:round}
    .spark-area{opacity:.15}
    .spark-line-green{stroke:#22c55e}.spark-area-green{fill:#22c55e}
    .spark-line-yellow{stroke:#eab308}.spark-area-yellow{fill:#eab308}
    .spark-line-red{stroke:#ef4444}.spark-area-red{fill:#ef4444}
    .spark-line-blue{stroke:#60a5fa}.spark-area-blue{fill:#60a5fa}

    .card-stats{display:flex;gap:16px;justify-content:center;width:100%;padding:8px 0 0;border-top:1px solid #1e293b}
    .card-stat{display:flex;flex-direction:column;align-items:center;gap:1px}
    .card-stat-value{font-size:.85rem;font-weight:700;color:#cbd5e1}
    .card-stat-label{font-size:.6rem;color:#64748b;text-transform:uppercase;letter-spacing:.5px}

    .card-links{display:flex;gap:10px;margin-top:4px}
    .card-link{font-size:.78rem;color:#94a3b8;text-decoration:none;padding:5px 12px;border:1px solid #1e293b;border-radius:8px;transition:color .2s,border-color .2s,background .2s}
    .card-link:hover{color:#e2e8f0;border-color:#3b82f6;background:rgba(59,130,246,.08)}
    .card-link.muted{color:#475569;cursor:default;pointer-events:none}

    .color-green{stroke:#22c55e}.color-yellow{stroke:#eab308}.color-red{stroke:#ef4444}.color-muted{stroke:#334155}
    .text-green{color:#22c55e}.text-yellow{color:#eab308}.text-red{color:#ef4444}.text-muted{color:#475569}

    footer{text-align:center;margin-top:48px;color:#334155;font-size:.8rem}
    footer a{color:#475569;text-decoration:none}footer a:hover{color:#64748b}
  </style>
</head>
<body>
  <div class="container">
    <header>
      <h1><span>${projectTitle}</span> Coverage</h1>
      <p>Test coverage across all stacks &mdash; updated on every push to <code>main</code></p>
      <div class="gate-legend">
        <span class="gate-legend-item"><span class="gate-legend-dot pass"></span> Gate passed (meets threshold)</span>
        <span class="gate-legend-item"><span class="gate-legend-dot fail"></span> Gate failed (below threshold)</span>
      </div>
    </header>
${heroCard}
    <div class="section-title">Coverage by stack</div>
    <div class="grid">
${cards}
    </div>
    <footer>
      <p>${footerParts.join(" · ")}</p>
    </footer>
  </div>
</body>
</html>`;
}

// ─── Main ───────────────────────────────────────────────────────────────────

function main() {
  console.log(`Scanning artifacts in: ${artifactsDir}`);
  const stacks = discoverStacks(artifactsDir);

  if (stacks.length === 0) {
    console.warn(
      "No stack directories found — generating empty dashboard.",
    );
  }

  console.log(
    `Found ${stacks.length} stack(s): ${stacks.map((s) => s.name).join(", ")}`,
  );

  for (const s of stacks) {
    const line = s.coverage.line ?? "N/A";
    const branch = s.coverage.branch ?? "N/A";
    console.log(`  ${s.icon} ${s.title}: line=${line}, branch=${branch}`);
  }

  const overall = {
    line: average(stacks.map((s) => s.coverage.line)),
    branch: average(stacks.map((s) => s.coverage.branch)),
  };

  console.log(
    `  🏆 Overall: line=${overall.line ?? "N/A"}, branch=${overall.branch ?? "N/A"}`,
  );

  // Load history and config
  const history = loadHistory(historyPath);
  const config = loadConfig(configPath);
  const previousRunCount = history.runs.length;

  console.log(
    `  📈 History: ${previousRunCount} previous run(s) loaded`,
  );

  // Append current run to history
  appendCurrentRun(history, stacks, overall);

  // Log deltas
  if (previousRunCount > 0) {
    const lineDelta = getOverallDelta(history, "line");
    const branchDelta = getOverallDelta(history, "branch");
    const fmtDelta = (d) =>
      d === null ? "N/A" : `${d > 0 ? "+" : ""}${d.toFixed(1)}%`;
    console.log(
      `  📊 Delta: line=${fmtDelta(lineDelta)}, branch=${fmtDelta(branchDelta)}`,
    );
  }

  // Log gates
  let allGatesPassed = true;
  for (const s of stacks) {
    const threshold = getGateThreshold(config, s.name);
    const linePct = pctToNumber(s.coverage.line);
    const lineDisplay = linePct === null ? "N/A" : `${linePct}%`;
    const passed = evaluateGate(linePct, threshold);
    const status =
      passed === null ? "⚠️  N/A" : passed ? "✅ Pass" : "❌ Fail";
    console.log(
      `  🚦 Gate ${s.name}: ${status} (${lineDisplay} ≥ ${threshold}%)`,
    );
    if (passed === false) {
      allGatesPassed = false;
    }
  }

  // Save updated history
  saveHistory(historyPath, history);
  if (historyPath) {
    console.log(
      `  💾 History saved: ${historyPath} (${history.runs.length} run(s))`,
    );
  }

  // Combined badge (average line coverage)
  const combinedPct = pctToNumber(overall.line);
  let combinedLabel = "N/A";
  let combinedColor = "#9f9f9f";

  if (combinedPct !== null) {
    combinedLabel = `${combinedPct.toFixed(1)}%`;
    combinedColor = badgeColor(combinedPct);
  }

  const badgeSvg = generateBadgeSvg(
    "coverage",
    combinedLabel,
    combinedColor,
  );
  const badgePath = join(artifactsDir, "badge_combined.svg");
  writeFileSync(badgePath, badgeSvg, "utf8");
  console.log(`Badge written: ${badgePath} (${combinedLabel})`);

  // Per-stack badges
  for (const s of stacks) {
    const pct = pctToNumber(s.coverage.line);
    const value = pct !== null ? `${pct.toFixed(1)}%` : "N/A";
    const color = pct !== null ? badgeColor(pct) : "#9f9f9f";
    const svg = generateBadgeSvg(s.name, value, color);
    const svgPath = join(artifactsDir, s.name, "badge_named.svg");
    writeFileSync(svgPath, svg, "utf8");
    console.log(`Badge written: ${svgPath} (${s.title}: ${value})`);
  }

  // Dashboard HTML
  const timestamp = new Date()
    .toUTCString()
    .replace(/\s*GMT$/, " UTC");
  const html = generateDashboardHtml(stacks, overall, timestamp, {
    history,
    config,
  });
  const htmlPath = join(artifactsDir, "index.html");
  writeFileSync(htmlPath, html, "utf8");
  console.log(`Dashboard written: ${htmlPath}`);

  // Report gate status
  if (!allGatesPassed) {
    console.warn(
      "\n⚠️  One or more coverage gates failed. See details above.",
    );
  }
}

main();
